var surah030 = {
  number: 30,
  nameArabic: "ar-Rum",
  nameEnglish: "Ar-Rum",
  meaning: "The Romans",
  totalAyahs: 60,
  ayahs: [
    { number: 1, arabic: "الٓمٓ", transliteration: "Aliflammeem", transliterationB: "Alif-Laaam-Meeem", english: "L. M", romanUrdu: "Alif Laam Meem" },
    { number: 2, arabic: "غُلِبَتِ ٱلرُّومُ", transliteration: "Ghulibati alrroomu", transliterationB: "Ghulibatir Room", english: "The Roman Empire has been defeated", romanUrdu: "Rumi (romans) qareeb ki sar-zameen mein magloob (defeat/overcome) ho gaye hain" },
    { number: 3, arabic: "فِىٓ أَدْنَى ٱلْأَرْضِ وَهُم مِّنۢ بَعْدِ غَلَبِهِمْ سَيَغْلِبُونَ", transliteration: "Fee adna alardi wahum min baAAdi ghalabihim sayaghliboona", transliterationB: "Feee adnal ardi wa hummim ba'di ghalabihim sa ya ghliboon", english: "In a land close by; but they, (even) after (this) defeat of theirs, will soon be victorious", romanUrdu: "Aur apni is magloobiyat (defeat) ke baad chandh saal ke andar woh gaalib (victorious/dominant) ho jayenge" },
    { number: 4, arabic: "فِى بِضْعِ سِنِينَ ۗ لِلَّهِ ٱلْأَمْرُ مِن قَبْلُ وَمِنۢ بَعْدُ ۚ وَيَوْمَئِذٍۢ يَفْرَحُ ٱلْمُؤْمِنُونَ", transliteration: "Fee bidAAi sineena lillahi alamru min qablu wamin baAAdu wayawmaithin yafrahu almuminoona", transliterationB: "Fee bid'i sineen; lillaahil amru min qablu wa mim ba'd; wa yawma'iziny yafrahul mu'minoon", english: "Within a few years. With Allah is the Decision, in the past and in the Future: on that Day shall the Believers rejoice", romanUrdu: "Allah hi ka ikhtiyar hai pehle bhi aur baad mein bhi. Aur woh din woh hoga jabke Allah ki bakshi hui fatah par musalmaan khushiyan manayenge" },
    { number: 5, arabic: "بِنَصْرِ ٱللَّهِ ۚ يَنصُرُ مَن يَشَآءُ ۖ وَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ", transliteration: "Binasri Allahi yansuru man yashao wahuwa alAAazeezu alrraheemu", transliterationB: "Binasril laa; yansuru mai yashaaa'u wa Huwal 'Azeezur Raheem", english: "With the help of Allah. He helps whom He will, and He is exalted in might, most merciful", romanUrdu: "Allah nusrat (victory) ata farmata hai jisey chahta hai, Aur woh zabardast aur raheem hai" },
    { number: 6, arabic: "وَعْدَ ٱللَّهِ ۖ لَا يُخْلِفُ ٱللَّهُ وَعْدَهُۥ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "WaAAda Allahi la yukhlifu Allahu waAAdahu walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Wa'dal laahi laa yukhliful laahu wa'dahoo wa laakin na aksaran naasi laa ya'lamoon", english: "(It is) the promise of Allah. Never does Allah depart from His promise: but most men understand not", romanUrdu: "Yeh wada Allah ne kiya hai, Allah kabhi apne wade ki khilaf warzi nahin karta. Magar aksar log nahin jaante hain" },
    { number: 7, arabic: "يَعْلَمُونَ ظَٰهِرًۭا مِّنَ ٱلْحَيَوٰةِ ٱلدُّنْيَا وَهُمْ عَنِ ٱلْءَاخِرَةِ هُمْ غَٰفِلُونَ", transliteration: "YaAAlamoona thahiran mina alhayati alddunya wahum AAani alakhirati hum ghafiloona", transliterationB: "Ya'lamoona zaahiram minal hayaatid dunya wa hum 'anil Aakhirati hum ghaafiloon", english: "They know but the outer (things) in the life of this world: but of the End of things they are heedless", romanUrdu: "Log duniya ki zindagi ka bas zaahiri pehlu (outward aspect) jaante hain aur aakhirat se woh khud hi gaafil hain" },
    { number: 8, arabic: "أَوَلَمْ يَتَفَكَّرُوا۟ فِىٓ أَنفُسِهِم ۗ مَّا خَلَقَ ٱللَّهُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَآ إِلَّا بِٱلْحَقِّ وَأَجَلٍۢ مُّسَمًّۭى ۗ وَإِنَّ كَثِيرًۭا مِّنَ ٱلنَّاسِ بِلِقَآئِ رَبِّهِمْ لَكَٰفِرُونَ", transliteration: "Awalam yatafakkaroo fee anfusihim ma khalaqa Allahu alssamawati waalarda wama baynahuma illa bialhaqqi waajalin musamman wainna katheeran mina alnnasi biliqai rabbihim lakafiroona", transliterationB: "Awalam yatafakkaroo feee anfusihim; maa khalaqal laahus samaawaati wal arda wa maa bainahumaaa illaa bil haqqi wa ajalim musammaa; wa inna kaseeram minan naasi biliqaaa'i Rabbihim lakaafiroon", english: "Do they not reflect in their own minds? Not but for just ends and for a term appointed, did Allah create the heavens and the earth, and all between them: yet are there truly many among men who deny the meeting with their Lord (at the Resurrection)", romanUrdu: "Kya unhon ne kabhi apne aap mein gaur-o-fikr nahin kiya? Allah ne zameen aur aasmaano ko aur un saari cheezon ko jo unke darmiyan hain barhaqq aur ek muqarrar muddat hi ke liye paida kiya hai. Magar bahut se log apne Rubb ki mulaqat ke munkir hain" },
    { number: 9, arabic: "أَوَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَانُوٓا۟ أَشَدَّ مِنْهُمْ قُوَّةًۭ وَأَثَارُوا۟ ٱلْأَرْضَ وَعَمَرُوهَآ أَكْثَرَ مِمَّا عَمَرُوهَا وَجَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ ۖ فَمَا كَانَ ٱللَّهُ لِيَظْلِمَهُمْ وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", transliteration: "Awalam yaseeroo fee alardi fayanthuroo kayfa kana AAaqibatu allatheena min qablihim kanoo ashadda minhum quwwatan waatharoo alarda waAAamarooha akthara mimma AAamarooha wajaathum rusuluhum bialbayyinati fama kana Allahu liyathlimahum walakin kanoo anfusahum yathlimoona", transliterationB: "Awalm yaseeroo fil ardi fa-yanzuroo kaifa kaana 'aaqibatul lazeena min qablihim; kaanooo ashadda minhhum quwwatanw wa asaarul arda wa 'amaroohaaa aksara mimmaa 'amaroohaa wa jaaa'athum Rusuluhum bil baiyinaati famaa kaanal laahu liyazli mahum wa laakin kaanooo anfusahum yazlimoon", english: "Do they not travel through the earth, and see what was the end of those before them? They were superior to them in strength: they tilled the soil and populated it in greater numbers than these have done: there came to them their messengers with Clear (Signs). (Which they rejected, to their own destruction): It was not Allah Who wronged them, but they wronged their own souls", romanUrdu: "Aur kya yeh log kabhi zameen mein chaley phirey nahin hain ke inhein un logon ka anjaam nazar aata jo insey pehle guzar chuke hain? Woh insey zyada taaqat rakhte thay. Unhon ne zameen ko khoob udheda(Tilled/prepare and cultivate (land) for crops) tha aur usey itna aabaad kiya tha jitna inhon ne nahin kiya hai. Unke paas unke Rasool roshan nishaniyan lekar aaye. Phir Allah unpar zulm karne wala na tha, magar woh khud hi apne upar zulm kar rahey thay" },
    { number: 10, arabic: "ثُمَّ كَانَ عَٰقِبَةَ ٱلَّذِينَ أَسَٰٓـُٔوا۟ ٱلسُّوٓأَىٰٓ أَن كَذَّبُوا۟ بِـَٔايَٰتِ ٱللَّهِ وَكَانُوا۟ بِهَا يَسْتَهْزِءُونَ", transliteration: "Thumma kana AAaqibata allatheena asaoo alssooa an kaththaboo biayati Allahi wakanoo biha yastahzioona", transliterationB: "Summa kaana'aaqibatal lazeena asaaa'us sooo aaa an kazzaboo bi aayaatil laahi wa kaanoo bihaa yastahzi'oon", english: "In the long run evil in the extreme will be the End of those who do evil; for that they rejected the Signs of Allah, and held them up to ridicule", romanUrdu: "Aakir e kaar jin logon ne buraiyan ki thi unka anjaam bahut bura hua. Isliye ke unhon ne Allah ki aayat ko jhutlaya tha aur woh unka mazaq udate thay" },
    { number: 11, arabic: "ٱللَّهُ يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ ثُمَّ إِلَيْهِ تُرْجَعُونَ", transliteration: "Allahu yabdao alkhalqa thumma yuAAeeduhu thumma ilayhi turjaAAoona", transliterationB: "Allaahu yabda'ul khalqa summa yu'eeduhoo summa ilaihi turja'oon", english: "It is Allah Who begins (the process of) creation; then repeats it; then shall ye be brought back to Him", romanUrdu: "Allah hi khalq ki ibtida(originates creation) karta hai, phir wahi iska iaada (phir paida/repeat) karega. Phir usi ki taraf tum paltaye jaogey" },
    { number: 12, arabic: "وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يُبْلِسُ ٱلْمُجْرِمُونَ", transliteration: "Wayawma taqoomu alssaAAatu yublisu almujrimoona", transliterationB: "Wa yawma taqoomus Saa'atu yublisul mujrimoon", english: "On the Day that the Hour will be established, the guilty will be struck dumb with despair", romanUrdu: "Aur jab woh sa-aat (hour/ghadi) barpa hogi us din mujrim hak-dak (dumbfounded) reh jayenge" },
    { number: 13, arabic: "وَلَمْ يَكُن لَّهُم مِّن شُرَكَآئِهِمْ شُفَعَٰٓؤُا۟ وَكَانُوا۟ بِشُرَكَآئِهِمْ كَٰفِرِينَ", transliteration: "Walam yakun lahum min shurakaihim shufaAAao wakanoo bishurakaihim kafireena", transliterationB: "Wa lam yakul lahum min shurakaaa'ihim shufa'aaa'u wa kaanoo bishurakaaa'ihim kaafireen", english: "No intercessor will they have among their \"Partners\" and they will (themselves) reject their \"Partners", romanUrdu: "Unke tehraye huey shareekon mein koi unka sifarishi (intercessor) na hoga, aur woh apne shareekon ke munkir ho jayenge" },
    { number: 14, arabic: "وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يَوْمَئِذٍۢ يَتَفَرَّقُونَ", transliteration: "Wayawma taqoomu alssaAAatu yawmaithin yatafarraqoona", transliterationB: "Wa Yawma taqoomus Saa'atu Yawma'iziny yatafarraqoon", english: "On the Day that the Hour will be established,- that Day shall (all men) be sorted out", romanUrdu: "Jis roz woh sa-aat (hour/ghadi/qayamat) barpa hogi, us din (sab Insaan) alag girohon mein batt(split ) jayenge" },
    { number: 15, arabic: "فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ فَهُمْ فِى رَوْضَةٍۢ يُحْبَرُونَ", transliteration: "Faamma allatheena amanoo waAAamiloo alssalihati fahum fee rawdatin yuhbaroona", transliterationB: "Fa ammal lazeena aamanoo wa 'amilus saalihaati fahum fee rawdatiny yuhbaroon", english: "Then those who have believed and worked righteous deeds, shall be made happy in a Mead of Delight", romanUrdu: "Jo log iman laye hain aur jinhon ne neik amal kiye hain woh ek baagh mein shadaan-o-farhaan (khush haal) rakkhey jayenge" },
    { number: 16, arabic: "وَأَمَّا ٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَٰتِنَا وَلِقَآئِ ٱلْءَاخِرَةِ فَأُو۟لَٰٓئِكَ فِى ٱلْعَذَابِ مُحْضَرُونَ", transliteration: "Waamma allatheena kafaroo wakaththaboo biayatina waliqai alakhirati faolaika fee alAAathabi muhdaroona", transliterationB: "Wa ammal lazeena kafaroo wa kazzaboo bi-Aayaatinaa wa liqaaa'il Aakhirati faulaaa'ika fil'azaabi muhdaroon", english: "And those who have rejected Faith and falsely denied our Signs and the meeting of the Hereafter,- such shall be brought forth to Punishment", romanUrdu: "Aur jinhon ne kufr kiya hai aur hamari aayat ko aur aakhirat ki mulaqaat ko jhutlaya woh azaab mein haazir rakkhey jayenge" },
    { number: 17, arabic: "فَسُبْحَٰنَ ٱللَّهِ حِينَ تُمْسُونَ وَحِينَ تُصْبِحُونَ", transliteration: "Fasubhana Allahi heena tumsoona waheena tusbihoona", transliterationB: "Fa Subhaanal laahi heena tumsoona wa heena tusbihoon", english: "So (give) glory to Allah, when ye reach eventide and when ye rise in the morning", romanUrdu: "Pas tasbeeh karo Allah ki jabke tum shaam karte ho aur jab subah karte ho" },
    { number: 18, arabic: "وَلَهُ ٱلْحَمْدُ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَعَشِيًّۭا وَحِينَ تُظْهِرُونَ", transliteration: "Walahu alhamdu fee alssamawati waalardi waAAashiyyan waheena tuthhiroona", transliterationB: "Wa lahul hamdu fis samaawaati wal ardi wa 'ashiyyanw wa heena tuzhiroon", english: "Yea, to Him be praise, in the heavens and on earth; and in the late afternoon and when the day begins to decline", romanUrdu: "Aasmaano aur zameen mein usi ke liye hamd(praise) hai aur (tasbeeh karo uski) teesre pehar aur jabke tumpar zohar ka waqt aata hai" },
    { number: 19, arabic: "يُخْرِجُ ٱلْحَىَّ مِنَ ٱلْمَيِّتِ وَيُخْرِجُ ٱلْمَيِّتَ مِنَ ٱلْحَىِّ وَيُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا ۚ وَكَذَٰلِكَ تُخْرَجُونَ", transliteration: "Yukhriju alhayya mina almayyiti wayukhriju almayyita mina alhayyi wayuhyee alarda baAAda mawtiha wakathalika tukhrajoona", transliterationB: "Yukhrijul haiya minal maiyiti wa yukhrijul maiyita minal haiyi wa yuhyil arda ba'da mawtihaa; wa kazaalika tukhrajoon", english: "It is He Who brings out the living from the dead, and brings out the dead from the living, and Who gives life to the earth after it is dead: and thus shall ye be brought out (from the dead)", romanUrdu: "Woh zinda mein se murde ko nikalta hai aur murde mein se zinda ko nikal laata hai aur zameen ko uski maut ke baat zindagi bakashta hai.Isi tarah tumlog bhi (haalat e maut se) nikaal liye jaogey" },
    { number: 20, arabic: "وَمِنْ ءَايَٰتِهِۦٓ أَنْ خَلَقَكُم مِّن تُرَابٍۢ ثُمَّ إِذَآ أَنتُم بَشَرٌۭ تَنتَشِرُونَ", transliteration: "Wamin ayatihi an khalaqakum min turabin thumma itha antum basharun tantashiroona", transliterationB: "Wa min Aayaatiheee an khalaqakum min turaabin summa izaaa antum basharun tantashiroon", english: "Among His Signs in this, that He created you from dust; and then,- behold, ye are men scattered (far and wide)", romanUrdu: "Uski nishaniyon mein se yeh hai ke usne tumko mitti se paida kiya phir yakayak tum bashar (Insaan) ho ke (zameen mein) phaylte chaley ja rahey ho" },
    { number: 21, arabic: "وَمِنْ ءَايَٰتِهِۦٓ أَنْ خَلَقَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًۭا لِّتَسْكُنُوٓا۟ إِلَيْهَا وَجَعَلَ بَيْنَكُم مَّوَدَّةًۭ وَرَحْمَةً ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَتَفَكَّرُونَ", transliteration: "Wamin ayatihi an khalaqa lakum min anfusikum azwajan litaskunoo ilayha wajaAAala baynakum mawaddatan warahmatan inna fee thalika laayatin liqawmin yatafakkaroona", transliterationB: "Wa min Aayaatiheee an khalaqa lakum min anfusikum azwaajal litaskunooo ilaihaa wa ja'ala bainakum mawad datanw wa rahmah; inna fee zaalika la Aayaatil liqawminy yatafakkaroon", english: "And among His Signs is this, that He created for you mates from among yourselves, that ye may dwell in tranquillity with them, and He has put love and mercy between your (hearts): verily in that are Signs for those who reflect", romanUrdu: "Aur uski nishaniyon mein se yeh hai ke unse tumhare liye tumhari jins se biwiyan banayi taa-ke tum unke paas sukoon hasil karo aur tumhare darmiyan mohabbat aur rehmat paida kardi. Yaqeenan is mein bahut si nishaniyan hain un logon ke liye jo gaur o fikr karte hain" },
    { number: 22, arabic: "وَمِنْ ءَايَٰتِهِۦ خَلْقُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَٰفُ أَلْسِنَتِكُمْ وَأَلْوَٰنِكُمْ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّلْعَٰلِمِينَ", transliteration: "Wamin ayatihi khalqu alssamawati waalardi waikhtilafu alsinatikum waalwanikum inna fee thalika laayatin lilAAalimeena", transliterationB: "Wa min Aayaatihee khalqus samaawaati wal aardi wakhtilaafu alsinatikum wa alwaanikum; inna fee zaalika la Aayaatil lil'aalimeen", english: "And among His Signs is the creation of the heavens and the earth, and the variations in your languages and your colours: verily in that are Signs for those who know", romanUrdu: "Aur uski nishaniyon mein se aasmaano aur zameen ki paidaish, aur tumhari zubaano aur tumhare rangon (colors) ka ikhtilaf hai. Yaqeenan is mein bahut si nishaniyan hain daanishmand (wise) logon ke liye" },
    { number: 23, arabic: "وَمِنْ ءَايَٰتِهِۦ مَنَامُكُم بِٱلَّيْلِ وَٱلنَّهَارِ وَٱبْتِغَآؤُكُم مِّن فَضْلِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَسْمَعُونَ", transliteration: "Wamin ayatihi manamukum biallayli waalnnahari waibtighaokum min fadlihi inna fee thalika laayatin liqawmin yasmaAAoona", transliterationB: "Wa min Aayaatihee manaamukum bil laili wannahaari wabtighaaa'ukum min fadlih; inna fee zaalika la Aayaatil liqawminy yasma'oon", english: "And among His Signs is the sleep that ye take by night and by day, and the quest that ye (make for livelihood) out of His Bounty: verily in that are signs for those who hearken", romanUrdu: "Aur uski nishaniyon mein se tumhara raat aur din ko sona aur tumhara uske fazal ko talash karna hai. Yaqeenan is mein bahut si nishaniyan hain un logon ke liye jo (gaur se) suntay hain" },
    { number: 24, arabic: "وَمِنْ ءَايَٰتِهِۦ يُرِيكُمُ ٱلْبَرْقَ خَوْفًۭا وَطَمَعًۭا وَيُنَزِّلُ مِنَ ٱلسَّمَآءِ مَآءًۭ فَيُحْىِۦ بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يَعْقِلُونَ", transliteration: "Wamin ayatihi yureekumu albarqa khawfan watamaAAan wayunazzilu mina alssamai maan fayuhyee bihi alarda baAAda mawtiha inna fee thalika laayatin liqawmin yaAAqiloona", transliterationB: "Wa min Aayaatihee yureekumul barqa khawfanw wa tama'anw wa yunazzilu minas samaaa'i maaa'an fa yuhyee bihil arda ba'da mawtihaaa inna fee zaalika la Aayaatil liqawminy ya'qiloon", english: "And among His Signs, He shows you the lightning, by way both of fear and of hope, and He sends down rain from the sky and with it gives life to the earth after it is dead: verily in that are Signs for those who are wise", romanUrdu: "Aur uski nishaniyon mein se yeh hai ke woh tumhein bijli ki chamak dikhata hai khauf ke saath bhi aur tamah (umeed) ke saath bhi. Aur aasmaan se pani barsata hai, Phir iske zariye se zameen ko uski maut ke baad zindagi bakshta hai. Yaqeenan is mein bahut si nishaniyan hain un logon ke liye jo aqal se kaam letay hain" },
    { number: 25, arabic: "وَمِنْ ءَايَٰتِهِۦٓ أَن تَقُومَ ٱلسَّمَآءُ وَٱلْأَرْضُ بِأَمْرِهِۦ ۚ ثُمَّ إِذَا دَعَاكُمْ دَعْوَةًۭ مِّنَ ٱلْأَرْضِ إِذَآ أَنتُمْ تَخْرُجُونَ", transliteration: "Wamin ayatihi an taqooma alssamao waalardu biamrihi thumma itha daAAakum daAAwatan mina alardi itha antum takhrujoona", transliterationB: "Wa min Aayaatihee an taqoomas samaaa'u wal ardu bi-amrih; summa izaa da'aakum da'watam minal ardi izaaa antum takhrujoon", english: "And among His Signs is this, that heaven and earth stand by His Command: then when He calls you, by a single call, from the earth, behold, ye (straightway) come forth", romanUrdu: "Aur uski nishaniyon mein se yeh hai ke aasmaan aur zameen uske hukum se qayam hain, phir junhi ke usne tumhein zameen se pukara, bas ek hi pukar mein achanak tum nikal aaogey" },
    { number: 26, arabic: "وَلَهُۥ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ كُلٌّۭ لَّهُۥ قَٰنِتُونَ", transliteration: "Walahu man fee alssamawati waalardi kullun lahu qanitoona", transliterationB: "Wa lahoo man fissamaawaati wal ardi kullul lahoo qaanitoon", english: "To Him belongs every being that is in the heavens and on earth: all are devoutly obedient to Him", romanUrdu: "Aasmaano aur zameen mein jo bhi hain uske bandey hain. Sab ke sab usi ke taabe-farmaan(obedient) hain" },
    { number: 27, arabic: "وَهُوَ ٱلَّذِى يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ وَهُوَ أَهْوَنُ عَلَيْهِ ۚ وَلَهُ ٱلْمَثَلُ ٱلْأَعْلَىٰ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Wahuwa allathee yabdao alkhalqa thumma yuAAeeduhu wahuwa ahwanu AAalayhi walahu almathalu alaAAla fee alssamawati waalardi wahuwa alAAazeezu alhakeemu", transliterationB: "Wa Huwal lazee yabda'ul khalqa summa yu'eeduhoo wa huwa ahwanu 'alaih; wa lahul masalul la'laa fissamaawaati wal-ard; wa Huwal 'Azeezul Hakeem", english: "It is He Who begins (the process of) creation; then repeats it; and for Him it is most easy. To Him belongs the loftiest similitude (we can think of) in the heavens and the earth: for He is Exalted in Might, full of wisdom", romanUrdu: "Wahi hai jo takhleeq ki ibtida karta hai, phir wahi uska iaada (phir paida/repeat) karega aur yeh uske liye aasaan tarr hai.Aasmaano aur zameen mein uski sifat (attribute) sabse bartar hai aur woh zabardast aur hakeem hai" },
    { number: 28, arabic: "ضَرَبَ لَكُم مَّثَلًۭا مِّنْ أَنفُسِكُمْ ۖ هَل لَّكُم مِّن مَّا مَلَكَتْ أَيْمَٰنُكُم مِّن شُرَكَآءَ فِى مَا رَزَقْنَٰكُمْ فَأَنتُمْ فِيهِ سَوَآءٌۭ تَخَافُونَهُمْ كَخِيفَتِكُمْ أَنفُسَكُمْ ۚ كَذَٰلِكَ نُفَصِّلُ ٱلْءَايَٰتِ لِقَوْمٍۢ يَعْقِلُونَ", transliteration: "Daraba lakum mathalan min anfusikum hal lakum mi mma malakat aymanukum min shurakaa fee ma razaqnakum faantum feehi sawaon takhafoonahum kakheefatikum anfusakum kathalika nufassilu alayati liqawmin yaAAqiloona", transliterationB: "Daraba lakum masalam min anfusikum hal lakum mimmaa malakat aymaanukum min shurakaaa'a fee maa razaqnaakum fa antum feehi sawaaa'un takhaafoonahum kakheefa tikum anfusakum; kazaalika nufassilul Aayaati liqawminy ya'qiloon", english: "He does propound to you a similitude from your own (experience): do ye have partners among those whom your right hands possess, to share as equals in the wealth We have bestowed on you? Do ye fear them as ye fear each other? Thus do we explain the Signs in detail to a people that understand", romanUrdu: "Woh tumhein khud tumhari apni hi zaat se ek misal deta hai. Kya tumhare un ghulaamo mein se jo tumhari milkiyat mein hain kuch ghulam aisey bhi hain jo hamare diye huey maal o daulat mein tumhare saath barabar ke shareek hon aur tum unsey us tarah darte ho jis tarah aapas mein apne humsaron (each other)se darte ho? Is tarah hum aayaat khol kar pesh karte hain un logon ke liye jo aqal se kaam letay hain" },
    { number: 29, arabic: "بَلِ ٱتَّبَعَ ٱلَّذِينَ ظَلَمُوٓا۟ أَهْوَآءَهُم بِغَيْرِ عِلْمٍۢ ۖ فَمَن يَهْدِى مَنْ أَضَلَّ ٱللَّهُ ۖ وَمَا لَهُم مِّن نَّٰصِرِينَ", transliteration: "Bali ittabaAAa allatheena thalamoo ahwaahum bighayri AAilmin faman yahdee man adalla Allahu wama lahum min nasireena", transliterationB: "Balit taba'al lazeena zalamooo ahwaaa'ahum bighairi 'ilmin famai yahdee man adallal laahu wa maa lahum min naasireen", english: "Nay, the wrong-doers (merely) follow their own lusts, being devoid of knowledge. But who will guide those whom Allah leaves astray? To them there will be no helpers", romanUrdu: "Magar yeh zaalim bay-samjhey boojhey apne takhailaat (desires) ke peechey chal padey hain. Ab kaun us shaks ko raasta dikha sakta hai jisey Allah ne bhatka diya ho. Aisey logon ka to koi madadgaar nahin ho sakta" },
    { number: 30, arabic: "فَأَقِمْ وَجْهَكَ لِلدِّينِ حَنِيفًۭا ۚ فِطْرَتَ ٱللَّهِ ٱلَّتِى فَطَرَ ٱلنَّاسَ عَلَيْهَا ۚ لَا تَبْدِيلَ لِخَلْقِ ٱللَّهِ ۚ ذَٰلِكَ ٱلدِّينُ ٱلْقَيِّمُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Faaqim wajhaka lilddeeni haneefan fitrata Allahi allatee fatara alnnasa AAalayha la tabdeela likhalqi Allahi thalika alddeenu alqayyimu walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Fa aqim wajhaka liddeeni Haneefaa; fitratal laahil latee fataran naasa 'alaihaa; laa taabdeela likhalqil laah; zaalikad deenul qaiyimu wa laakinna aksaran naasi laa ya'lamoon", english: "So set thou thy face steadily and truly to the Faith: (establish) Allah's handiwork according to the pattern on which He has made mankind: no change (let there be) in the work (wrought) by Allah: that is the standard Religion: but most among mankind understand not", romanUrdu: "Pas (Aey Nabi, aur Nabi ke pairawon) yaksu hokar apna rukh is deen ki simth mein jamaa do. Qayam ho jao us fitrat par jispar Allah taala ne Insano ko paida kiya hai. Allah ki banayi hui saakht badli nahin jaa sakti. Yahi bilkul raast aur durust deen hai, magar aksar log jaante nahin hain" },
    { number: 31, arabic: "۞ مُنِيبِينَ إِلَيْهِ وَٱتَّقُوهُ وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَلَا تَكُونُوا۟ مِنَ ٱلْمُشْرِكِينَ", transliteration: "Muneebeena ilayhi waittaqoohu waaqeemoo alssalata wala takoonoo mina almushrikeena", transliterationB: "Muneebeena ilaihi wattaqoohu wa aqeemus Salaata wa laa takoonoo minal mushrikeen", english: "Turn ye back in repentance to Him, and fear Him: establish regular prayers, and be not ye among those who join gods with Allah", romanUrdu: "(Qayam ho jao is baat par)Allah ki taraf rujoo karte huey, aur daro ussey, aur namaz qayam karo , aur na ho jao un mushrikeen mein se" },
    { number: 32, arabic: "مِنَ ٱلَّذِينَ فَرَّقُوا۟ دِينَهُمْ وَكَانُوا۟ شِيَعًۭا ۖ كُلُّ حِزْبٍۭ بِمَا لَدَيْهِمْ فَرِحُونَ", transliteration: "Mina allatheena farraqoo deenahum wakanoo shiyaAAan kullu hizbin bima ladayhim farihoona", transliterationB: "Minal lazeena farraqoo deenahum wa kaanoo shiya'an kullu hizbim bimaa ladaihim farihoon", english: "Those who split up their Religion, and become (mere) Sects,- each party rejoicing in that which is with itself", romanUrdu: "Jinhon ne apna apna deen alag bana liya hai aur girohon (firkon) mein batt gaye hain. Har ek giroh ke paas jo kuch hai usi mein woh magan hai" },
    { number: 33, arabic: "وَإِذَا مَسَّ ٱلنَّاسَ ضُرٌّۭ دَعَوْا۟ رَبَّهُم مُّنِيبِينَ إِلَيْهِ ثُمَّ إِذَآ أَذَاقَهُم مِّنْهُ رَحْمَةً إِذَا فَرِيقٌۭ مِّنْهُم بِرَبِّهِمْ يُشْرِكُونَ", transliteration: "Waitha massa alnnasa durrun daAAaw rabbahum muneebeena ilayhi thumma itha athaqahum minhu rahmatan itha fareequn minhum birabbihim yushrikoona", transliterationB: "Wa izaa massan naasa durrun da'aw Rabbahum muneebeena ilaihi summa izaaa azaqahum minhu rahmatan izaa fareequm minhum be Rabbihim yushrikoon", english: "When trouble touches men, they cry to their Lord, turning back to Him in repentance: but when He gives them a taste of Mercy as from Himself, behold, some of them pay part-worship to other god's besides their Lord", romanUrdu: "Logon ka haal yeh hai ke jab unhein koi takleef pahunchi hai to apne Rubb ki taraf rujoo karke usey pukarte hain, phir jab woh kuch apne rehmat ka zaika (taste) unhein chakha deta hai to yakayak un mein se kuch log shirk karne lagte hain" },
    { number: 34, arabic: "لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَٰهُمْ ۚ فَتَمَتَّعُوا۟ فَسَوْفَ تَعْلَمُونَ", transliteration: "Liyakfuroo bima ataynahum fatamattaAAoo fasawfa taAAlamoona", transliterationB: "Li yakfuroo bimaaa aatainaahum; fatamatta'oo fasawfa ta'lamoon", english: "(As if) to show their ingratitude for the (favours) We have bestowed on them! Then enjoy (your brief day); but soon will ye know (your folly)", romanUrdu: "Taa-ke hamare kiye huey ehsan ki nashukri karein. Accha, mazey karlo, anqareeb tumhein maaloom ho jayega" },
    { number: 35, arabic: "أَمْ أَنزَلْنَا عَلَيْهِمْ سُلْطَٰنًۭا فَهُوَ يَتَكَلَّمُ بِمَا كَانُوا۟ بِهِۦ يُشْرِكُونَ", transliteration: "Am anzalna AAalayhim sultanan fahuwa yatakallamu bima kanoo bihi yushrikoona", transliterationB: "Am anzalnaa 'alaihim sultaanan fahuwa yatakallamu bimaa kaanoo bihee yushrikoon", english: "Or have We sent down authority to them, which points out to them the things to which they pay part-worship", romanUrdu: "Kya humne koi sanad aur daleel unpar nazil ki hai jo shahadat deti ho us shirk ki sadaqat par jo yeh kar rahey hain" },
    { number: 36, arabic: "وَإِذَآ أَذَقْنَا ٱلنَّاسَ رَحْمَةًۭ فَرِحُوا۟ بِهَا ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ إِذَا هُمْ يَقْنَطُونَ", transliteration: "Waitha athaqna alnnasa rahmatan farihoo biha wain tusibhum sayyiatun bima qaddamat aydeehim itha hum yaqnatoona", transliterationB: "Wa izaaa azaqnan naasa rahmatan farihoo bihaa wa in tusibhum sayyi'atum bimaa qaddamat aydeehim izaa hum yaqnatoon", english: "When We give men a taste of Mercy, they exult thereat: and when some evil afflicts them because of what their (own) hands have sent forth, behold, they are in despair", romanUrdu: "Jab hum logon ko rehmat ka zaika chakhate hain to woh uspar phool jatey hain, aur jab unke apne kiya kartooton se unpar koi museebat aati hai to yakayak woh mayous honay lagte hain" },
    { number: 37, arabic: "أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Awalam yaraw anna Allaha yabsutu alrrizqa liman yashao wayaqdiru inna fee thalika laayatin liqawmin yuminoona", transliterationB: "Awalam yaraw annal laaha yabsutur rizqa limai yashaaa'u wa yaqdir; inna fee zaalika la Aayaatil liqawminy yu'minoon", english: "See they not that Allah enlarges the provision and restricts it, to whomsoever He pleases? Verily in that are Signs for those who believe", romanUrdu: "Kya yeh log dekhte nahin hain ke Allah hi rizq kushada karta hai jiska chahta hai aur tangg karta hai (jiska chahta hai)? Yaqeenan is mein bahut si nishaniyan hain un logon ke liye jo iman latey hain" },
    { number: 38, arabic: "فَـَٔاتِ ذَا ٱلْقُرْبَىٰ حَقَّهُۥ وَٱلْمِسْكِينَ وَٱبْنَ ٱلسَّبِيلِ ۚ ذَٰلِكَ خَيْرٌۭ لِّلَّذِينَ يُرِيدُونَ وَجْهَ ٱللَّهِ ۖ وَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Faati tha alqurba haqqahu waalmiskeena waibna alssabeeli thalika khayrun lillatheena yureedoona wajha Allahi waolaika humu almuflihoona", transliterationB: "Fa aati zal qurbaa haqqahoo walmiskeena wabnassabeel; zaalika khairul lil lazeena yureedoona Wajhal laahi wa ulaaa'ika humul muflihoon", english: "So give what is due to kindred, the needy, and the wayfarer. That is best for those who seek the Countenance, of Allah, and it is they who will prosper", romanUrdu: "Pas (aey momin) rishtedar ko uska haqq de aur miskeen o musafir ko (uska haqq). Yeh tareeqa behtar hai un logon ke liye jo Allah ki khushnudi chahte hon, aur wahi falaah paney waley hain" },
    { number: 39, arabic: "وَمَآ ءَاتَيْتُم مِّن رِّبًۭا لِّيَرْبُوَا۟ فِىٓ أَمْوَٰلِ ٱلنَّاسِ فَلَا يَرْبُوا۟ عِندَ ٱللَّهِ ۖ وَمَآ ءَاتَيْتُم مِّن زَكَوٰةٍۢ تُرِيدُونَ وَجْهَ ٱللَّهِ فَأُو۟لَٰٓئِكَ هُمُ ٱلْمُضْعِفُونَ", transliteration: "Wama ataytum min riban liyarbuwa fee amwali alnnasi fala yarboo AAinda Allahi wama ataytum min zakatin tureedoona wajha Allahi faolaika humu almudAAifoona", transliterationB: "Wa maaa aataitum mir ribal li yarbuwa feee amwaalin naasi falaa yarboo 'indal laahi wa maaa aataitum min zaakaatin tureedoona wajhal laahi fa ulaaa'ika humul mud'ifoon", english: "That which ye lay out for increase through the property of (other) people, will have no increase with Allah: but that which ye lay out for charity, seeking the Countenance of Allah, (will increase): it is these who will get a recompense multiplied", romanUrdu: "Jo sood (riba /usury /interest) tum detay ho taa-ke logon ke amwal mein shamil hokar woh badh (increase) jaye, Allah ke nazdeek woh nahin badhta (increase), aur jo zakaat tum Allah ki khushnudi haasil karne ke iradey se detey ho, usi ke dene waley dar haqeeqat apne maal badhate hain" },
    { number: 40, arabic: "ٱللَّهُ ٱلَّذِى خَلَقَكُمْ ثُمَّ رَزَقَكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ۖ هَلْ مِن شُرَكَآئِكُم مَّن يَفْعَلُ مِن ذَٰلِكُم مِّن شَىْءٍۢ ۚ سُبْحَٰنَهُۥ وَتَعَٰلَىٰ عَمَّا يُشْرِكُونَ", transliteration: "Allahu allathee khalaqakum thumma razaqakum thumma yumeetukum thumma yuhyeekum hal min shurakaikum man yafAAalu min thalikum min shayin subhanahu wataAAala AAamma yushrikoona", transliterationB: "Allaahul lazee khalaqa kum summa razaqakm summa yumeetukum summa yuhyeekum hal min shurakaaa'ikum mai yaf'alu min zaalikum min shai'; Sub haanahoo wa Ta'aalaa 'ammaa yushrikoon", english: "It is Allah Who has created you: further, He has provided for your sustenance; then He will cause you to die; and again He will give you life. Are there any of your (false) \"Partners\" who can do any single one of these things? Glory to Him! and high is He above the partners they attribute (to him)", romanUrdu: "Allah hi hai jisne tumko paida kiya, phir tumhein rizq diya, phir woh tumhein maut deta hai, phir woh tumhein zinda karega. Kya tumhare thehraye huey shareekon mein koi aisa hai jo in mein se koi kaam bhi karta ho? Paak hai woh aur bahut baala-o-bartar hai us shirk se jo yeh log karte hain" },
    { number: 41, arabic: "ظَهَرَ ٱلْفَسَادُ فِى ٱلْبَرِّ وَٱلْبَحْرِ بِمَا كَسَبَتْ أَيْدِى ٱلنَّاسِ لِيُذِيقَهُم بَعْضَ ٱلَّذِى عَمِلُوا۟ لَعَلَّهُمْ يَرْجِعُونَ", transliteration: "Thahara alfasadu fee albarri waalbahri bima kasabat aydee alnnasi liyutheeqahum baAAda allathee AAamiloo laAAallahum yarjiAAoona", transliterationB: "Zaharal fasaadu fil barri wal bahri bimaa kasabat aydinnaasi li yuzeeqahum ba'dal lazee 'amiloo la'allahum yarji'oon", english: "Mischief has appeared on land and sea because of (the meed) that the hands of men have earned, that (Allah) may give them a taste of some of their deeds: in order that they may turn back (from Evil)", romanUrdu: "Khushki (land) aur tarii (sea) mein fasaad barpa ho gaya hai logon ke apne haathon ki kamayi se, taa-ke maza chakkhaye unko unke baaz aamal ka, shayad ke woh baaz aayein" },
    { number: 42, arabic: "قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلَّذِينَ مِن قَبْلُ ۚ كَانَ أَكْثَرُهُم مُّشْرِكِينَ", transliteration: "Qul seeroo fee alardi faonthuroo kayfa kana AAaqibatu allatheena min qablu kana aktharuhum mushrikeena", transliterationB: "Qul seeroo fil ardi fanzuroo kaifa kaana 'aaqibatul lazeena min qabl; kaana aksaruhum mushrikeen", english: "Say: \"Travel through the earth and see what was the end of those before (you): Most of them worshipped others besides Allah", romanUrdu: "(Aey Nabi) insey kaho ke zameen mein chal phir kar dekho pehle guzre huey logon ka kya anjaam ho chuka hai. Un mein se aksar mushrik hi thay" },
    { number: 43, arabic: "فَأَقِمْ وَجْهَكَ لِلدِّينِ ٱلْقَيِّمِ مِن قَبْلِ أَن يَأْتِىَ يَوْمٌۭ لَّا مَرَدَّ لَهُۥ مِنَ ٱللَّهِ ۖ يَوْمَئِذٍۢ يَصَّدَّعُونَ", transliteration: "Faaqim wajhaka lilddeeni alqayyimi min qabli an yatiya yawmun la maradda lahu mina Allahi yawmaithin yassaddaAAoona", transliterationB: "Fa aqim wajhaka lid deenil qaiyimi min qabli any yaatiya Yawmul laa maradda lahoo minal laahi Yawma'iziny yassadda'oon", english: "But set thou thy face to the right Religion before there come from Allah the Day which there is no chance of averting: on that Day shall men be divided (in two)", romanUrdu: "Pas (Aey Nabi) apna rukh mazbooti ke saath jamaa do is deen-e-raast ki simth mein qabl iske ke woh din aaye jiske tal janey ki koi surat Allah ki taraf se nahin hai.Us din log phatt kar ek dusre se alag ho jayenge" },
    { number: 44, arabic: "مَن كَفَرَ فَعَلَيْهِ كُفْرُهُۥ ۖ وَمَنْ عَمِلَ صَٰلِحًۭا فَلِأَنفُسِهِمْ يَمْهَدُونَ", transliteration: "Man kafara faAAalayhi kufruhu waman AAamila salihan falianfusihim yamhadoona", transliterationB: "Man kafara fa'alaihi kufruhoo wa man 'amila saalihan fali anfusihim yamhadoon", english: "Those who reject Faith will suffer from that rejection: and those who work righteousness will spread their couch (of repose) for themselves (in heaven)", romanUrdu: "Jisne kufr kiya hai uske kufr ka wabal usi par hai, aur jin logon ne neik amal kiya hai woh apne hi liye falaah ka raasta saaf kar rahey hain" },
    { number: 45, arabic: "لِيَجْزِىَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ مِن فَضْلِهِۦٓ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْكَٰفِرِينَ", transliteration: "Liyajziya allatheena amanoo waAAamiloo alssalihati min fadlihi innahu la yuhibbu alkafireena", transliterationB: "Li yajziyal lazeena aamanoo wa 'amilus saalihaati min fadlih; innahoo laa yuhibbul kaafireen", english: "That He may reward those who believe and work righteous deeds, out of his Bounty. For He loves not those who reject Faith", romanUrdu: "Taa-ke Allah imaan laney walon aur amal-e-saleh karne walon ko apne fazal se jaza de. Yaqeenan woh kaafiron ko pasand nahin karta" },
    { number: 46, arabic: "وَمِنْ ءَايَٰتِهِۦٓ أَن يُرْسِلَ ٱلرِّيَاحَ مُبَشِّرَٰتٍۢ وَلِيُذِيقَكُم مِّن رَّحْمَتِهِۦ وَلِتَجْرِىَ ٱلْفُلْكُ بِأَمْرِهِۦ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ", transliteration: "Wamin ayatihi an yursila alrriyaha mubashshiratin waliyutheeqakum min rahmatihi walitajriya alfulku biamrihi walitabtaghoo min fadlihi walaAAallakum tashkuroona", transliterationB: "Wa min Aayaatiheee anyyursilar riyaaha mubashshi raatinw wa li yuzeeqakum mir rahmatihee wa litajriyal fulku bi amrihee wa litabtaghoo min fadlihee wa la'allakum tashkuroon", english: "Among His Signs is this, that He sends the Winds, as heralds of Glad Tidings, giving you a taste of His (Grace and) Mercy,- that the ships may sail (majestically) by His Command and that ye may seek of His Bounty: in order that ye may be grateful", romanUrdu: "Uski nishaniyon mein se yeh hai ke woh hawaein bhejhta hai basharat ke liye aur tumhein apni rehmat se behramand karne ke liye. Aur is garz ke liye ke kashtiyan uske hukum se chalein aur tum uska fazal talash karo aur uske shukar guzar banoo" },
    { number: 47, arabic: "وَلَقَدْ أَرْسَلْنَا مِن قَبْلِكَ رُسُلًا إِلَىٰ قَوْمِهِمْ فَجَآءُوهُم بِٱلْبَيِّنَٰتِ فَٱنتَقَمْنَا مِنَ ٱلَّذِينَ أَجْرَمُوا۟ ۖ وَكَانَ حَقًّا عَلَيْنَا نَصْرُ ٱلْمُؤْمِنِينَ", transliteration: "Walaqad arsalna min qablika rusulan ila qawmihim fajaoohum bialbayyinati faintaqamna mina allatheena ajramoo wakana haqqan AAalayna nasru almumineena", transliterationB: "Wa laqad arsalnaa min qablika Rusulan ilaa qawmihim fajaaa'oohum bil baiyinaati fantaqamnaa minal lazeena ajramoo wa kaana haqqan 'alainaa nasrul mu'mineen", english: "We did indeed send, before thee, messengers to their (respective) peoples, and they came to them with Clear Signs: then, to those who transgressed, We meted out Retribution: and it was due from Us to aid those who believed", romanUrdu: "Aur humne tumse pehle Rasoolon ko unki qaum ki taraf bheja aur woh unke paas roshan nishaniyan lekar aaye. Phir jinhon ne jurm kiya unsey humne inteqaam liya aur humpar yeh haqq tha ke hum momino ki madad karein" },
    { number: 48, arabic: "ٱللَّهُ ٱلَّذِى يُرْسِلُ ٱلرِّيَٰحَ فَتُثِيرُ سَحَابًۭا فَيَبْسُطُهُۥ فِى ٱلسَّمَآءِ كَيْفَ يَشَآءُ وَيَجْعَلُهُۥ كِسَفًۭا فَتَرَى ٱلْوَدْقَ يَخْرُجُ مِنْ خِلَٰلِهِۦ ۖ فَإِذَآ أَصَابَ بِهِۦ مَن يَشَآءُ مِنْ عِبَادِهِۦٓ إِذَا هُمْ يَسْتَبْشِرُونَ", transliteration: "Allahu allathee yursilu alrriyaha fatutheeru sahaban fayabsutuhu fee alssamai kayfa yashao wayajAAaluhu kisafan fatara alwadqa yakhruju min khilalihi faitha asaba bihi man yashao min AAibadihi itha hum yastabshiroona", transliterationB: "Allaahul lazee yursilur riyaaha fatuseeru sahaaban fa yabsutuhoo fis samaaa'i kaifa yashaaa'u wa yaj'aluhoo kisafan fataral wadqa yakhruju min khilaalihee fa izaaa asaaba bihee mai yashaaa'u min 'ibaadiheee izaa hum yastabshiroon", english: "It is Allah Who sends the Winds, and they raise the Clouds: then does He spread them in the sky as He wills, and break them into fragments, until thou seest rain-drops issue from the midst thereof: then when He has made them reach such of his servants as He wills behold, they do rejoice", romanUrdu: "Allah hi hai jo hawaon ko bhejta hai aur woh baadal uthati hain. Phir woh in baadalon ko aasmaan mein phaila deta hai jis tarah chahta hai, aur unhein tukdiyon mein takseem karta hai, phir tu dekhta hai ke baarish ke qatray baadal se tapke chale aate hain. Yeh baarish jab woh apne bandon mein se jinpar chahta hai barsata hai" },
    { number: 49, arabic: "وَإِن كَانُوا۟ مِن قَبْلِ أَن يُنَزَّلَ عَلَيْهِم مِّن قَبْلِهِۦ لَمُبْلِسِينَ", transliteration: "Wain kanoo min qabli an yunazzala AAalayhim min qablihi lamubliseena", transliterationB: "Wa in kaanoo min qabli any yunazzala 'alaihim min qablihee lamubliseen", english: "Even though, before they received (the rain) - just before this - they were dumb with despair", romanUrdu: "To yakayak woh khush o khurram ho jatey hain , halaanke iske nuzul se pehle woh mayous ho rahey thay" },
    { number: 50, arabic: "فَٱنظُرْ إِلَىٰٓ ءَاثَٰرِ رَحْمَتِ ٱللَّهِ كَيْفَ يُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ ذَٰلِكَ لَمُحْىِ ٱلْمَوْتَىٰ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌۭ", transliteration: "Faonthur ila athari rahmati Allahi kayfa yuhyee alarda baAAda mawtiha inna thalika lamuhyee almawta wahuwa AAala kulli shayin qadeerun", transliterationB: "Fanzur ilaaa aasaari rahmatil laahi kaifa yuhyil arda ba'da mawtihaa; inna zaalika lamuhyil mawtaa wa Huwa 'alaa kulli shai'in Qadeer", english: "Then contemplate (O man!) the memorials of Allah's Mercy!- how He gives life to the earth after its death: verily the same will give life to the men who are dead: for He has power over all things", romanUrdu: "Dekho Allah ki rehmat ke asraat , ke murda padi hui zameen ko woh kis taraah jila uthata hai, yaqeenan woh murdon ko zindagi bakshne wala hai aur woh har cheez par qadir hai" },
    { number: 51, arabic: "وَلَئِنْ أَرْسَلْنَا رِيحًۭا فَرَأَوْهُ مُصْفَرًّۭا لَّظَلُّوا۟ مِنۢ بَعْدِهِۦ يَكْفُرُونَ", transliteration: "Walain arsalna reehan faraawhu musfarran lathalloo min baAAdihi yakfuroona", transliterationB: "Wa la'in arsalnaa reehan fara awhu musfarral lazalloo mim ba'dihee yakfuroon", english: "And if We (but) send a Wind from which they see (their tilth) turn yellow,- behold, they become, thereafter, Ungrateful (Unbelievers)", romanUrdu: "Aur agar hum ek aisi hawa bhej dein jiske asar se woh apni kheti ko zard paayein to woh kufr karte reh jaate hain" },
    { number: 52, arabic: "فَإِنَّكَ لَا تُسْمِعُ ٱلْمَوْتَىٰ وَلَا تُسْمِعُ ٱلصُّمَّ ٱلدُّعَآءَ إِذَا وَلَّوْا۟ مُدْبِرِينَ", transliteration: "Fainnaka la tusmiAAu almawta wala tusmiAAu alssumma aldduAAaa itha wallaw mudbireena", transliterationB: "Fa innaka laa tusmi'ul mawtaa wa laa tusmi'us summad du'aaa'a izaa wallaw mudbireen", english: "So verily thou canst not make the dead to hear, nor canst thou make the deaf to hear the call, when they show their backs and turn away", romanUrdu: "(Aey Nabi) Tum murdon ko nahin suna sakte, na unn behron ko apni pukar suna sakte ho jo peeth pherey bhaagay chaley jaa rahe hon" },
    { number: 53, arabic: "وَمَآ أَنتَ بِهَٰدِ ٱلْعُمْىِ عَن ضَلَٰلَتِهِمْ ۖ إِن تُسْمِعُ إِلَّا مَن يُؤْمِنُ بِـَٔايَٰتِنَا فَهُم مُّسْلِمُونَ", transliteration: "Wama anta bihadi alAAumyi AAan dalalatihim in tusmiAAu illa man yuminu biayatina fahum muslimoona", transliterationB: "Wa maa anta bihaadil 'umyi 'an dalaalatihim in tusmi'u illaa mai yuminu bi aayaatinaa fahum muslimoon", english: "Nor canst thou lead back the blind from their straying: only those wilt thou make to hear, who believe in Our signs and submit (their wills in Islam)", romanUrdu: "Aur na tum andhon ko unki gumrahi se nikaal kar raah e raast dikha sakte ho, tum to sirf unhi ko suna sakte ho jo hamari aayat par iman latey aur sar-e-tasleem kham kar detey hain" },
    { number: 54, arabic: "۞ ٱللَّهُ ٱلَّذِى خَلَقَكُم مِّن ضَعْفٍۢ ثُمَّ جَعَلَ مِنۢ بَعْدِ ضَعْفٍۢ قُوَّةًۭ ثُمَّ جَعَلَ مِنۢ بَعْدِ قُوَّةٍۢ ضَعْفًۭا وَشَيْبَةًۭ ۚ يَخْلُقُ مَا يَشَآءُ ۖ وَهُوَ ٱلْعَلِيمُ ٱلْقَدِيرُ", transliteration: "Allahu allathee khalaqakum min daAAfin thumma jaAAala min baAAdi daAAfin quwwatan thumma jaAAala min baAAdi quwwatin daAAfan washaybatan yakhluqu ma yashao wahuwa alAAaleemu alqadeeru", transliterationB: "Allahul lazee khalaqa kum min du'fin summa ja'ala mim ba'di du'fin quwwatan summa ja'ala mim ba'di quwwatin du'fanw wa shaibah; yakhluqu maa yashaaa'u wa Huwal 'Aleemul Qadeer", english: "It is Allah Who created you in a state of (helpless) weakness, then gave (you) strength after weakness, then, after strength, gave (you weakness and a hoary head: He creates as He wills, and it is He Who has all knowledge and power)", romanUrdu: "Allah hi to hai jisne zoaf (kamzori) ki haalat mein tumhari paidaish ki ibtida ki, phir is zoaf (kamzori) ke baad tumhein quwwat bakshi, phir is quwwat ke baad tumhein zaeef aur buda (old) kardiya. Woh jo kuch chahta hai paida karta hai, aur woh sabkuch janne wala, har cheez par qudrat rakhta hai" },
    { number: 55, arabic: "وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يُقْسِمُ ٱلْمُجْرِمُونَ مَا لَبِثُوا۟ غَيْرَ سَاعَةٍۢ ۚ كَذَٰلِكَ كَانُوا۟ يُؤْفَكُونَ", transliteration: "Wayawma taqoomu alssaAAatu yuqsimu almujrimoona ma labithoo ghayra saAAatin kathalika kanoo yufakoona", transliterationB: "Wa Yawma taqoomus Saa'atu yuqsimul mujrimoona maa labisoo ghaira saa'ah; kazaalika kaanoo yu'fakoon", english: "On the Day that the Hour (of Reckoning) will be established, the transgressors will swear that they tarried not but an hour: thus were they used to being deluded", romanUrdu: "Aur jab woh sa-aat (hour) barpa hogi to mujrim kasmein kha kha kar kahenge ke hum ek ghadi bhar se zyada nahin thehre hain.Isi taraah woh duniya ki zindagi mein dhoka khaya karte thay" },
    { number: 56, arabic: "وَقَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ وَٱلْإِيمَٰنَ لَقَدْ لَبِثْتُمْ فِى كِتَٰبِ ٱللَّهِ إِلَىٰ يَوْمِ ٱلْبَعْثِ ۖ فَهَٰذَا يَوْمُ ٱلْبَعْثِ وَلَٰكِنَّكُمْ كُنتُمْ لَا تَعْلَمُونَ", transliteration: "Waqala allatheena ootoo alAAilma waaleemana laqad labithtum fee kitabi Allahi ila yawmi albaAAthi fahatha yawmu albaAAthi walakinnakum kuntum la taAAlamoona", transliterationB: "Wa qaalal lazeena ootul 'ilma wal eemaana laqad labistum fee kitaabil laahi ilaa yawmil ba'si fahaazaa yawmul ba'si wa laakinnakum kuntum laa ta'lamoon", english: "But those endued with knowledge and faith will say: \"Indeed ye did tarry, within Allah's Decree, to the Day of Resurrection, and this is the Day of Resurrection: but ye - ye were not aware", romanUrdu: "Magar jo ilm aur iman se behramand (endowed) kiye gaye thay woh kahenge ke khuda ke nawishte (record) mein to tum roz-e-hashar tak paday rahey ho. So yeh wahi roz-e-hashar hai, lekin tum jante na thay" },
    { number: 57, arabic: "فَيَوْمَئِذٍۢ لَّا يَنفَعُ ٱلَّذِينَ ظَلَمُوا۟ مَعْذِرَتُهُمْ وَلَا هُمْ يُسْتَعْتَبُونَ", transliteration: "Fayawmaithin la yanfaAAu allatheena thalamoo maAAthiratuhum wala hum yustaAAtaboona", transliterationB: "Fa Yawma'izil laa yanfa'ul lazeena zalamoo ma'ziratu hum wa laa hum yusta'taboon", english: "So on that Day no excuse of theirs will avail the transgressors, nor will they be invited (then) to seek grace (by repentance)", romanUrdu: "Pas woh din hoga jismein zaalimon ko unki maazrat koi nafa (faida) na degi aur na unsey maafi maangne ke liye kaha jayega" },
    { number: 58, arabic: "وَلَقَدْ ضَرَبْنَا لِلنَّاسِ فِى هَٰذَا ٱلْقُرْءَانِ مِن كُلِّ مَثَلٍۢ ۚ وَلَئِن جِئْتَهُم بِـَٔايَةٍۢ لَّيَقُولَنَّ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ أَنتُمْ إِلَّا مُبْطِلُونَ", transliteration: "Walaqad darabna lilnnasi fee hatha alqurani min kulli mathalin walain jitahum biayatin layaqoolanna allatheena kafaroo in antum illa mubtiloona", transliterationB: "Wa laqad darabnaa linnaasi fee haazal Quraani min kulli masal; wa la'in ji'tahum bi aayatil la yaqoolannal lazeena kafaroo in antum illaa mubtiloon", english: "verily We have propounded for men, in this Qur'an every kind of Parable: But if thou bring to them any Sign, the Unbelievers are sure to say, \"Ye do nothing but talk vanities", romanUrdu: "Humne is Quran mein logon ko tarah tarah se samjhaya hai, tum khwah koi nishani le aao, jin logon ne maanne se inkar kardiya hai wo yahi kahenge ke tum baatil(falsehood) par ho" },
    { number: 59, arabic: "كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ قُلُوبِ ٱلَّذِينَ لَا يَعْلَمُونَ", transliteration: "Kathalika yatbaAAu Allahu AAala quloobi allatheena la yaAAlamoona", transliterationB: "Kazaalika yatba'ul laahu 'alaa quloobil lazeena laa ya'lamoon", english: "Thus does Allah seal up the hearts of those who understand not", romanUrdu: "Is tarah thappa (seal) laga deta hai Allah un logon ke dilon par jo be-ilm hain" },
    { number: 60, arabic: "فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّۭ ۖ وَلَا يَسْتَخِفَّنَّكَ ٱلَّذِينَ لَا يُوقِنُونَ", transliteration: "Faisbir inna waAAda Allahi haqqun wala yastakhiffannaka allatheena la yooqinoona", transliterationB: "Fasbir inna wa'dal laahi haqqunw wa laa yastakhif fannakal lazeena laa yooqinoon", english: "So patiently persevere: for verily the promise of Allah is true: nor let those shake thy firmness, who have (themselves) no certainty of faith", romanUrdu: "Pas (Aey Nabi) sabr karo, yaqeenan Allah ka wada sachha hai. Aur hargiz halka na payein tumko woh log jo yaqeen nahin laatey" }
  ]
};
